    names[index + 1] = "p_deaths_nonaids_hivpop";
    ret[index + 1] = r_p_deaths_nonaids_hivpop;
    Rcpp::NumericVector r_p_excess_deaths_nonaids_on_art(SS::pAG * SS::NS * output_years);
