  static Config::State get_initial_state(
    const Rcpp::List &data
  ) {
    typename Config::State state;
    state.total_population = Rcpp::as<real_type>(data["total_population"]);
    state.total_population_dp = Rcpp::as<real_type>(data["total_population_dp"]);
    fill_initial_state<real_type, typename Config::State::shape_adults>(data, "adults", state.adults);
    fill_initial_state<real_type, typename Config::State::shape_adults_ts>(data, "adults_ts", state.adults_ts);
    fill_initial_state<real_type, typename Config::State::shape_pop_hiv_neg>(data, "pop_hiv_neg", state.pop_hiv_neg);
    fill_initial_state<real_type, typename Config::State::shape_cured_pop>(data, "cured_pop", state.cured_pop);
    fill_initial_state<real_type, typename Config::State::shape_cured_prop>(data, "cured_prop", state.cured_prop);
    fill_initial_state<real_type, typename Config::State::shape_deaths>(data, "deaths", state.deaths);
    state.total_deaths = Rcpp::as<real_type>(data["total_deaths"]);
    state.total_deaths_hiv = Rcpp::as<real_type>(data["total_deaths_hiv"]);
    fill_initial_state<real_type, typename Config::State::shape_deaths_hiv>(data, "deaths_hiv", state.deaths_hiv);
    fill_initial_state<real_type, typename Config::State::shape_new_infections>(data, "new_infections", state.new_infections);
    state.total_new_infections = Rcpp::as<real_type>(data["total_new_infections"]);
    state.new_infections_dp = Rcpp::as<real_type>(data["new_infections_dp"]);
    fill_initial_state<real_type, typename Config::State::shape_incidence_goals>(data, "incidence_goals", state.incidence_goals);
    fill_initial_state<real_type, typename Config::State::shape_new_infections_goals>(data, "new_infections_goals", state.new_infections_goals);
    fill_initial_state<real_type, typename Config::State::shape_prevalence>(data, "prevalence", state.prevalence);
    state.total_prevalence = Rcpp::as<real_type>(data["total_prevalence"]);
    fill_initial_state<real_type, typename Config::State::shape_newly_on_art>(data, "newly_on_art", state.newly_on_art);
    state.total_on_art = Rcpp::as<real_type>(data["total_on_art"]);
    state.total_plhiv = Rcpp::as<real_type>(data["total_plhiv"]);
    fill_initial_state<real_type, typename Config::State::shape_mult_no_art>(data, "mult_no_art", state.mult_no_art);
    fill_initial_state<real_type, typename Config::State::shape_mult_art>(data, "mult_art", state.mult_art);
    fill_initial_state<real_type, typename Config::State::shape_new_inf_vrs>(data, "new_inf_vrs", state.new_inf_vrs);
    fill_initial_state<real_type, typename Config::State::shape_new_inf_s>(data, "new_inf_s", state.new_inf_s);
    fill_initial_state<real_type, typename Config::State::shape_num_people_reached>(data, "num_people_reached", state.num_people_reached);
    fill_initial_state<real_type, typename Config::State::shape_resources_required>(data, "resources_required", state.resources_required);
    fill_initial_state<real_type, typename Config::State::shape_new_inf_scale_factor>(data, "new_inf_scale_factor", state.new_inf_scale_factor);
    state.total_new_vaccinations = Rcpp::as<real_type>(data["total_new_vaccinations"]);
    state.total_vaccinated = Rcpp::as<real_type>(data["total_vaccinated"]);
    return state;
  };

